const input = $json || {};
const zalo_user_id = String(input.zalo_user_id || '').trim();
const zalo_msg_id = String(input.zalo_msg_id || '').trim();
const file_url = String(input.file_url || '').trim();
const xml_text = typeof input.xml_text === 'string' ? input.xml_text : '';
const supplier_guess = input.supplier_guess ? String(input.supplier_guess).trim() : null;
const channel = String(input.channel || 'zalo');
const source_type = String(input.source_type || 'xml');
const source_url = String(input.source_url || file_url || 'inline://xml_text');

if (!zalo_user_id) throw new Error('zalo_user_id is required');
if (!zalo_msg_id) throw new Error('zalo_msg_id is required');
if (!file_url && !xml_text) throw new Error('file_url or xml_text is required');

if (file_url) {
  let parsed;
  try { parsed = new URL(file_url); } catch { throw new Error('file_url must be a valid URL'); }
  if (parsed.protocol !== 'https:') throw new Error('file_url must use https');
  const allowHosts = String($env.ALLOWED_FILE_URL_HOSTS || '').split(',').map(s => s.trim()).filter(Boolean);
  if (allowHosts.length && !allowHosts.includes(parsed.hostname)) {
    throw new Error('file_url host is not allowlisted');
  }
}

return [{ json: { zalo_user_id, zalo_msg_id, file_url, xml_text, supplier_guess, channel, source_type, source_url } }];

const input = $('Validate Inputs').item.json;
return [{ json: {
  duplicate: true,
  signal: 'duplicate',
  zalo_user_id: input.zalo_user_id,
  zalo_msg_id: input.zalo_msg_id,
  message: 'Duplicate invoice message detected. Skipped.'
}}];

const ctx = $('Validate Inputs').item.json;
const root = $json.Invoice || $json.invoice || $json;

const supplierCode = root?.Supplier?.Code || root?.SupplierCode || root?.supplier_code || ctx.supplier_guess || 'UNKNOWN_SUPPLIER';
const supplierName = root?.Supplier?.Name || root?.SupplierName || supplierCode;
const invoiceNumber = root?.InvoiceNumber || root?.invoice_number || null;
const invoiceDate = root?.InvoiceDate || root?.invoice_date || new Date().toISOString().slice(0, 10);

const rawItems = root?.Items?.Item || root?.items?.item || root?.items || [];
const itemArray = Array.isArray(rawItems) ? rawItems : (rawItems ? [rawItems] : []);

const normalizeBool = (v) => String(v).toLowerCase() === 'true' || String(v) === '1';
const n = (v, fallback = 0) => {
  const x = Number(v);
  return Number.isFinite(x) ? x : fallback;
};

const items = itemArray.map((it, idx) => {
  const quantity = n(it.Quantity ?? it.quantity, 0);
  const unitPrice = n(it.UnitPrice ?? it.unit_price, 0);
  const totalAmount = n(it.TotalAmount ?? it.total_amount, quantity * unitPrice);

  return {
    line_number: n(it.LineNumber ?? it.line_number, idx + 1),
    supplier_item_code: String(it.SupplierItemCode ?? it.supplier_item_code ?? it.ItemCode ?? `item_${idx + 1}`),
    item_name: String(it.ItemName ?? it.item_name ?? 'Unknown Item'),
    quantity,
    unit: String(it.Unit ?? it.unit ?? ''),
    unit_price: unitPrice,
    total_amount: totalAmount,
    is_promotion: normalizeBool(it.IsPromotion ?? it.is_promotion ?? false),
    barcode: it.Barcode ?? it.barcode ?? null,
    confidence_score: 100
  };
});

const totalBill = items.reduce((sum, it) => sum + Number(it.total_amount || 0), 0);
const parsedInvoice = {
  supplier_name: supplierName,
  supplier_code: supplierCode,
  invoice_number: invoiceNumber,
  invoice_date: invoiceDate,
  items,
  total_bill_amount: totalBill,
  raw_source: 'xml',
  llm_overall_confidence: 100
};

const elapsed = Math.max(0, Date.now() - Number(ctx.started_at || Date.now()));
return [{ json: {
  ...ctx,
  duplicate: false,
  parsed_invoice: parsedInvoice,
  parsed_data_sql: JSON.stringify(parsedInvoice).replace(/'/g, "''"),
  supplier_code_sql: String(parsedInvoice.supplier_code || '').replace(/'/g, "''"),
  source_url_sql: String(ctx.file_url || '').replace(/'/g, "''"),
  processing_time_ms: elapsed
}}];

return [{ json: {
  duplicate: false,
  signal: 'processed',
  zalo_user_id: $json.zalo_user_id,
  zalo_msg_id: $json.zalo_msg_id,
  parsed_invoice: $json.parsed_invoice
}}];

const xml = $('Validate Inputs').item.json.xml_text || '';
const base64 = Buffer.from(xml, 'utf8').toString('base64');
return [{ json: $('Validate Inputs').item.json, binary: { data: { data: base64, mimeType: 'application/xml', fileName: 'telegram-inline.xml' } } }];
